class _BarChart(QtWidgets.QWidget):
    def __init__(self, data, parent=None):
        """data: list of (label, pct)"""
        super().__init__(parent)
        self._data = data
        self.setMinimumHeight(240)

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)

        w, h = self.width(), self.height()
        m_left, m_right, m_top, m_bottom = 32, 8, 24, 36
        chart_w = w - m_left - m_right
        chart_h = h - m_top - m_bottom
        max_val = 100

        # Gridlines + axis labels
        axis_font = QtGui.QFont("Segoe UI", 8)
        p.setFont(axis_font)
        for i in range(6):
            val = i * 20
            y = m_top + chart_h - (val / max_val) * chart_h
            p.setPen(QtGui.QPen(QtGui.QColor("#eef0f4"), 1))
            p.drawLine(QtCore.QPointF(m_left, y), QtCore.QPointF(w - m_right, y))
            p.setPen(QtGui.QPen(QtGui.QColor(_TEXT_GREY)))
            p.drawText(QtCore.QRectF(0, y - 8, m_left - 6, 16),
                       Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
                       str(val))

        n = len(self._data)
        if n == 0:
            p.end(); return
        slot_w = chart_w / n
        bar_w = min(slot_w * 0.42, 46)

        for i, (label, pct) in enumerate(self._data):
            bar_h = (pct / max_val) * chart_h
            x = m_left + i * slot_w + (slot_w - bar_w) / 2
            y = m_top + chart_h - bar_h

            grad = QtGui.QLinearGradient(0, y, 0, m_top + chart_h)
            grad.setColorAt(0, QtGui.QColor("#6d84ff"))
            grad.setColorAt(1, QtGui.QColor("#3648c9"))
            p.setPen(Qt.PenStyle.NoPen)
            p.setBrush(QtGui.QBrush(grad))
            p.drawRoundedRect(QtCore.QRectF(x, y, bar_w, bar_h), 4, 4)

            p.setPen(QtGui.QPen(QtGui.QColor(_TEXT_DARK)))
            p.setFont(QtGui.QFont("Segoe UI", 9, QtGui.QFont.Weight.Bold))
            p.drawText(QtCore.QRectF(x - 12, y - 18, bar_w + 24, 16),
                       Qt.AlignmentFlag.AlignCenter, f"{pct}%")

            p.setPen(QtGui.QPen(QtGui.QColor(_TEXT_GREY)))
            p.setFont(QtGui.QFont("Segoe UI", 8))
            label_rect = QtCore.QRectF(m_left + i * slot_w - 14, m_top + chart_h + 6,
                                       slot_w + 28, 28)
            p.drawText(label_rect,
                       int(Qt.AlignmentFlag.AlignHCenter | Qt.AlignmentFlag.AlignTop |
                           Qt.TextFlag.TextWordWrap),
                       label)
        p.end()


