class _DonutChart(QtWidgets.QWidget):
    def __init__(self, data, center_value, center_label, parent=None):
        """data: list of (label, value, color)"""
        super().__init__(parent)
        self._data = data
        self._center_value = center_value
        self._center_label = center_label
        self.setMinimumSize(170, 170)

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)

        side = min(self.width(), self.height()) - 12
        rect = QtCore.QRectF((self.width() - side) / 2, (self.height() - side) / 2,
                             side, side)
        thickness = side * 0.24
        inner = rect.adjusted(thickness / 2, thickness / 2,
                              -thickness / 2, -thickness / 2)

        total = sum(v for _, v, _ in self._data) or 1
        start_angle = 90 * 16
        for label, val, color in self._data:
            span = -(val / total) * 360 * 16
            pen = QtGui.QPen(QtGui.QColor(color), thickness)
            pen.setCapStyle(Qt.PenCapStyle.FlatCap)
            p.setPen(pen)
            p.drawArc(inner, int(start_angle), int(span))
            start_angle += span

        cx, cy = rect.center().x(), rect.center().y()
        p.setPen(QtGui.QColor(_TEXT_DARK))
        p.setFont(QtGui.QFont("Segoe UI", 21, QtGui.QFont.Weight.Bold))
        p.drawText(QtCore.QRectF(rect.x(), cy - 22, rect.width(), 28),
                   Qt.AlignmentFlag.AlignCenter, str(self._center_value))
        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.setFont(QtGui.QFont("Segoe UI", 9))
        p.drawText(QtCore.QRectF(rect.x(), cy + 6, rect.width(), 18),
                   Qt.AlignmentFlag.AlignCenter, self._center_label)
        p.end()


